            except KeyboardInterrupt:
                print(f"\n{Fore.YELLOW}Прерывание...{Style.RESET_ALL}")
                break
            except Exception as e:
                logger.error(f"Ошибка: {e}")

async def main():
    """Запуск"""
    manager = YulaBotManager()
    await manager.run()

if __name__ == "__main__":
