            badge = self.driver.find_element("xpath", "//span[@class='messages-badge']")
            count = int(badge.text)
            self.unread_count = count
            return count
        except:
            self.unread_count = 0
            return 0

    def detect_new_messages(self) -> list:
        """📭 Обнаружить новые сообщения"""
        try:
            messages = self.driver.find_elements("xpath", "//div[@class='message-item']")
            detected = []

            for msg in messages:
                try:
                    sender = msg.find_element("xpath", ".//span[@class='sender']").text
                    text = msg.find_element("xpath", ".//span[@class='text']").text
                    time_str = msg.find_element("xpath", ".//span[@class='time']").text

                    message_data = {
                        'sender': sender,
                        'text': text,
                        'time': time_str,
                        'detected_at': datetime.now().isoformat(),
                    }

                    detected.append(message_data)
                    self._log_message(message_data)

                except:
                    continue

            self.last_messages = detected
            return detected

        except:
            return []

    def _log_message(self, message_data: dict):
        """💾 Логировать сообщение"""
        log_file = self.messages_log_dir / f"{self.account_id}_messages.json"

        try:
            if log_file.exists():
                with open(log_file, 'r', encoding='utf-8') as f:
                    messages = json.load(f)
            else:
                messages = []

            messages.append(message_data)

            with open(log_file, 'w', encoding='utf-8') as f:
                json.dump(messages, f, indent=2, ensure_ascii=False)

            self.logger.important(f"📞 От: {message_data['sender']}")
            self.logger.important(f"💬 Текст: {message_data['text'][:50]}...")

        except Exception as e:
            self.logger.error(f"Ошибка логирования: {e}")

    def update_message_status(self):
        """📊 Обновить статус сообщений"""
        count = self.check_unread_messages()

        if count > 0:
            self.logger.alert(f"🔴 {self.account_id}: {count} НЕПРОЧИТАННЫХ СООБЩЕНИЙ! ⭐")
            self.detect_new_messages()
        else:
            self.logger.success(f"✅ {self.account_id}: сообщений нет")

        return count

    def get_unread_count(self) -> int:
        """Получить количество непрочитанных"""
        return self.unread_count

    def has_unread_messages(self) -> bool:
        """Есть ли непрочитанные сообщения"""
        return self.unread_count > 0
