class BlockerDetector:
    """⚠️ ДЕТЕКТОР БЛОКИРОВОК"""

    def __init__(self, driver):
        self.driver = driver
        self.logger = Logger("BlockerDetector")
        self.is_blocked = False
        self.block_reason = None

    def check_captcha(self) -> bool:
