            self.logger.alert("🤖 ОБНАРУЖЕНА КАПЧА!")
            self.is_blocked = True
            self.block_reason = "CAPTCHA"
            return True
        except:
            return False

    def check_temporary_block(self) -> bool:
        """⏳ Проверить временную блокировку"""
        try:
            self.driver.find_element("xpath", "//div[contains(text(), 'Подождите')]")
            self.logger.alert("⏳ ВРЕМЕННАЯ БЛОКИРОВКА!")
            self.is_blocked = True
            self.block_reason = "TEMPORARY_BLOCK"
            return True
        except:
            return False

    def check_verification_required(self) -> bool:
        """✅ Проверить требование верификации"""
        try:
            self.driver.find_element("xpath", "//div[contains(text(), 'верификация')]")
            self.logger.alert("✅ ТРЕБУЕТСЯ ВЕРИФИКАЦИЯ!")
            self.is_blocked = True
            self.block_reason = "VERIFICATION_REQUIRED"
            return True
        except:
            return False

    def check_ip_blocked(self) -> bool:
        """🌍 Проверить блокировку IP"""
        try:
            self.driver.find_element("xpath", "//div[contains(text(), 'IP')]")
            self.logger.alert("🌍 IP ЗАБЛОКИРОВАН!")
            self.is_blocked = True
            self.block_reason = "IP_BLOCKED"
            return True
        except:
            return False

    def full_check(self) -> dict:
        """🔍 Полная проверка на блокировки"""
        checks = {
            'captcha': self.check_captcha(),
            'temporary_block': self.check_temporary_block(),
            'verification': self.check_verification_required(),
            'ip_blocked': self.check_ip_blocked(),
        }

        if any(checks.values()):
            self.logger.alert(f"❌ ОБНАРУЖЕНА БЛОКИРОВКА: {self.block_reason}")
            return {'blocked': True, 'checks': checks, 'reason': self.block_reason}

        return {'blocked': False, 'checks': checks, 'reason': None}

    def wait_for_unblock(self, timeout: int = 300):
        """⏳ Ждать разблокировки (5 мин по умолчанию)"""
        self.logger.warning(f"⏳ Жду разблокировки ({timeout} сек)...")
        time.sleep(timeout)

        if self.full_check()['blocked']:
            self.logger.alert("❌ Всё ещё заблокирован!")
            return False

        self.logger.success("✅ Разблокирован!")
        self.is_blocked = False
        self.block_reason = None
        return True
