import time
import random
from datetime import datetime
from .logger import Logger
from config import POST_LISTING_CONFIG

class SleepManager:
    """😴 УПРАВЛЕНИЕ СНОМ (РЕАЛИСТИЧНОЕ ПОВЕДЕНИЕ)"""

    def __init__(self, account_id: str):
        self.logger = Logger(f"SleepManager_{account_id}")
        self.account_id = account_id
        self.sleep_enabled = POST_LISTING_CONFIG['sleep_enabled']
        self.sleep_start_hour = POST_LISTING_CONFIG['sleep_start_hour']
        self.sleep_end_hour = POST_LISTING_CONFIG['sleep_end_hour']
        self.sleep_duration_min = POST_LISTING_CONFIG['sleep_duration_min']
        self.sleep_duration_max = POST_LISTING_CONFIG['sleep_duration_max']
        self.is_sleeping = False

    def should_sleep_now(self) -> bool:
        """🌙 Нужно ли спать сейчас"""
        if not self.sleep_enabled:
            return False

        current_hour = datetime.now().hour

        if self.sleep_start_hour > self.sleep_end_hour:
            # Сон переходит через полночь (23:00 - 08:00)
            return current_hour >= self.sleep_start_hour or current_hour < self.sleep_end_hour
        else:
            return self.sleep_start_hour <= current_hour < self.sleep_end_hour

    def go_to_sleep(self):
        """😴 Уснуть"""
        if not self.sleep_enabled:
            return

        sleep_time = random.randint(self.sleep_duration_min, self.sleep_duration_max)
        sleep_time_hours = sleep_time / 60

        self.is_sleeping = True
        self.logger.warning(f"😴 Спок... спю {sleep_time_hours:.1f} часов")

        time.sleep(sleep_time)

        self.is_sleeping = False
        self.logger.success(f"🌅 Проснулся!")

    def get_sleep_time_until_wake(self) -> int:
        """⏰ Время до пробуждения (в секундах)"""
        now = datetime.now()

        if self.sleep_start_hour > self.sleep_end_hour:
            if now.hour >= self.sleep_start_hour:
                # Спим до утра
                wake_time = now.replace(hour=self.sleep_end_hour, minute=0, second=0)
                if wake_time < now:
                    wake_time = wake_time.replace(day=wake_time.day + 1)
            else:
                # Спим с прошлой ночи
                wake_time = now.replace(hour=self.sleep_end_hour, minute=0, second=0)
        else:
            wake_time = now.replace(hour=self.sleep_end_hour, minute=0, second=0)

        sleep_seconds = (wake_time - now).total_seconds()
        return max(0, int(sleep_seconds))
