        """✅ Пора переиндексировать объявление"""
        if self.last_reindex is None:
            return True

        time_since_reindex = datetime.now() - self.last_reindex
        min_interval = POST_LISTING_CONFIG['reindex_interval_min']

        return time_since_reindex.total_seconds() >= min_interval

    def should_edit(self) -> bool:
        """✅ Пора редактировать объявление"""
        if self.last_edit is None:
            return True

        time_since_edit = datetime.now() - self.last_edit
        min_interval = POST_LISTING_CONFIG['edit_interval_min']

        return time_since_edit.total_seconds() >= min_interval

    def should_view_competitors(self) -> bool:
        """✅ Пора смотреть конкурентов"""
        if self.last_competitor_view is None:
            return True

        time_since_view = datetime.now() - self.last_competitor_view
        min_interval = 3600  # 1 час минимум

        return time_since_view.total_seconds() >= min_interval

    def should_check_messages(self) -> bool:
        """✅ Пора проверить сообщения"""
        if self.last_message_check is None:
            return True

        time_since_check = datetime.now() - self.last_message_check
        min_interval = POST_LISTING_CONFIG['check_messages_interval_min']

        return time_since_check.total_seconds() >= min_interval

    def get_next_check_in(self) -> int:
        """⏰ Когда следующая проверка (в секундах)"""
        if self.last_message_check is None:
            return 0

        time_since = datetime.now() - self.last_message_check
        min_interval = POST_LISTING_CONFIG['check_messages_interval_min']
        next_check = min_interval - time_since.total_seconds()

        return max(0, int(next_check))

    def mark_reindex(self):
        """Mark reindex time"""
        self.last_reindex = datetime.now()
        self.logger.success(f"✅ Переиндексирование отмечено")

    def mark_edit(self):
        """Mark edit time"""
        self.last_edit = datetime.now()
        self.logger.success(f"✅ Редактирование отмечено")

